Future<bool> confirm(BuildContext c,String msg)async=> await showDialog<bool>(context:c,builder:(_)=>AlertDialog(title:const Text('Onay'),content:Text(msg),actions:[TextButton(onPressed:()=>Navigator.pop(c,false),child:const Text('İptal')),FilledButton(onPressed:()=>Navigator.pop(c,true),child:const Text('Sil'))]))??false;
